patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index c112fae35181..3b51b9e322ee 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8638,6 +8638,31 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       if (FCmpInst::isEquality(Pred) && match(RHSC, m_AnyZeroFP()) &&
           match(LHSI, m_c_Select(m_FNeg(m_Value(X)), m_Deferred(X))))
         return replaceOperand(I, 0, X);
+      // fcmp pred (select (fcmp ord/uno X, _), X/Z, Z/X), W
+      //   -> fcmp pred X, W
+      // if pred is ordered (except ORD) and fcmp pred Z, W simplifies to false.
+      // When X is NaN, the ordered fcmp with X returns false. If comparing Z
+      // with W also yields false, then both paths give the same result.
+      if (FCmpInst::isOrdered(Pred) && Pred != FCmpInst::FCMP_ORD) {
+        auto *SI = cast<SelectInst>(LHSI);
+        Value *X = nullptr, *Z = nullptr;
+        CmpPredicate CondPred;
+        if (match(SI->getCondition(), m_FCmp(CondPred, m_Value(X), m_Value()))) {
+          if (CondPred == FCmpInst::FCMP_ORD &&
+              SI->getTrueValue() == X)
+            Z = SI->getFalseValue();
+          else if (CondPred == FCmpInst::FCMP_UNO &&
+                   SI->getFalseValue() == X)
+            Z = SI->getTrueValue();
+        }
+        if (Z) {
+          if (Value *V = simplifyFCmpInst(Pred, Z, Op1, I.getFastMathFlags(),
+                                          SQ.getWithInstruction(&I))) {
+            if (match(V, m_Zero()))
+              return replaceOperand(I, 0, X);
+          }
+        }
+      }
       if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
         return NV;
       break;

